@ARTICLE{10.1126/sciadv.adz1385,
	author = {Hu R(1)(2) and Park J(1) and Qian Y(1) and Xiong S(1) and Elsabbagh AH(1) and Chhikara A(1) and Fan H(1)(3) and Shi Z(1)(2) and Liu L(1) and Li Y(4) and Song Z(4) and Mahmoud AM(5) and Chen J(6) and Baur JA(7) and He Y(8) and Layden BT(5)(9) and Zhou Z(10)(11) and Xu P(5) and Ong SG(12)(13) and Wang Z(14) and Jiang Y(1)(2)(5).},
	title = {ERα activates NAMPT/IL-33 signaling to enhance beige thermogenesis and metabolic fitness.},
	abstract = {Beige adipocytes are inducible thermogenic fat cells that emerge within white adipose tissue (WAT) in response to thermogenic stimuli and confer metabolic benefits. However, obesity impairs the generation of beige adipocytes, and the underlying mechanisms remain poorly understood. Here, we show that obesity leads to a loss of adipose progenitor cells (APCs) in WAT, accompanied by reduced estrogen (E2) levels and nicotinamide phosphoribosyltransferase (NAMPT) expression. Supplementation with E2 or nicotinamide mononucleotide (NMN), an NAMPT-derived nicotinamide adenine dinucleotide (NAD+) precursor, restores beige adipogenesis in diet-induced obese mice. Mechanistically, estrogen receptor α (ERα) in APCs is required for beige fat formation by promoting Nampt transcription. We further demonstrate that NAMPT is both necessary and sufficient to drive APC proliferation and differentiation, with interleukin-33 (IL-33) acting downstream to mediate these effects. These findings uncover a critical ERα/NAMPT/IL-33 axis that preserves progenitor function and thermogenic capacity, offering a potential therapeutic strategy to combat obesity-induced beige fat failure and associated metabolic dysfunction.},
	doi = {10.1126/sciadv.adz1385},
	pmid = {41499496 [Indexed for MEDLINE]},
	note = {PMC12778055}
}

